"""Universal cross-module search screen."""


def render_search_page() -> str:
    return '''<!doctype html><html lang="sr"><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Pretraga · Balkan.works</title><style>:root{--ink:#092c26;--pine:#0d4036;--paper:#fbfaf6;--orange:#ff6c37;--line:#d9e3dc;--muted:#62746e;--mint:#e5f5eb}*{box-sizing:border-box}body{margin:0;background:var(--paper);font-family:Inter,system-ui;color:var(--ink)}.wrap{max-width:1050px;margin:auto;padding:0 22px}.nav{height:76px;border-bottom:1px solid var(--line);display:flex;align-items:center;justify-content:space-between}.brand{font-size:24px;font-weight:900;text-decoration:none;color:var(--ink)}.brand i{color:var(--orange)}.nav a:last-child{color:var(--pine);font-weight:800;text-decoration:none;font-size:14px}.hero{padding:50px 0 25px}.eyebrow{font-size:12px;color:var(--orange);letter-spacing:1.4px;font-weight:900;text-transform:uppercase}h1{font:clamp(40px,6vw,66px)/.98 Georgia,serif;letter-spacing:-2.3px;margin:13px 0}.lead{color:var(--muted);font-size:17px}.form{background:#fff;border:1px solid var(--line);border-radius:15px;padding:13px;display:grid;grid-template-columns:2fr 1fr 1fr auto;gap:9px}.form input,.form select{font:inherit;border:1px solid var(--line);border-radius:8px;padding:12px}.form button{background:var(--orange);color:#fff;border:0;border-radius:8px;padding:12px 17px;font-weight:900;cursor:pointer}.result{background:#fff;border:1px solid var(--line);border-radius:13px;padding:17px;margin:12px 0;text-decoration:none;color:var(--ink);display:block}.result:hover{border-color:#8bb5a1}.tag{display:inline-block;background:var(--mint);color:#18704f;border-radius:99px;padding:5px 8px;font-size:11px;font-weight:900}.result h2{font-size:20px;margin:8px 0}.result p{color:var(--muted);margin:5px 0;line-height:1.45}.meta{font-size:13px;color:#587069}.price{color:var(--orange);font-weight:900;float:right}.empty{color:var(--muted);padding:30px 0}@media(max-width:700px){.form{grid-template-columns:1fr 1fr}.form input{grid-column:span 2}.form button{grid-column:span 2}}</style><main class="wrap"><nav class="nav"><a class="brand" href="/">balkan<i>.</i>works</a><a href="/dashboard">Moj Balkan →</a></nav><header class="hero"><div class="eyebrow">Jedna pretraga · ceo ekosistem</div><h1>Pronađi šta ti treba.</h1><p class="lead">Market, Deals, Save Food i lokalne firme — filtrirano po tvojoj državi i gradu.</p></header><section class="form"><input id="q" placeholder="npr. električar, pločice, ručak, akcija…"><select id="country"><option value="">Sve države</option></select><input id="city" placeholder="Grad"><button id="go">Pretraži</button></section><section id="results"><div class="empty">Unesi pojam ili izaberi lokaciju.</div></section></main><script>const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));const money=(p,c)=>p==null?'':Number(p).toLocaleString('sr-RS',{style:'currency',currency:c||'EUR'});async function setup(){try{const c=await fetch('/api/locations/countries').then(r=>r.json());document.querySelector('#country').innerHTML='<option value="">Sve države</option>'+c.map(x=>'<option value="'+x.code+'">'+x.name+'</option>').join('')}catch(_){}}async function search(){const q=document.querySelector('#q').value.trim(),country=document.querySelector('#country').value,city=document.querySelector('#city').value.trim(),params=new URLSearchParams();if(q)params.set('q',q);if(country)params.set('country_code',country);if(city)params.set('city_name',city);const target=document.querySelector('#results');target.innerHTML='<div class="empty">Pretražujemo ekosistem…</div>';try{const data=await fetch('/api/search?'+params).then(r=>r.json());const results=data.results||[];target.innerHTML=results.length?results.map(x=>'<a class="result" href="'+x.url+'"><span class="tag">'+esc(x.module)+'</span><span class="price">'+money(x.price,x.currency)+'</span><h2>'+esc(x.title)+'</h2><p>'+esc(x.description||'')+'</p><div class="meta">'+esc(x.city_name||'Balkan')+', '+esc(x.country_code||'')+'</div></a>').join(''):'<div class="empty">Nema rezultata. Probaj drugi pojam ili širu lokaciju.</div>'}catch(_){target.innerHTML='<div class="empty">Pretraga trenutno nije dostupna.</div>'}}document.querySelector('#go').onclick=search;document.querySelector('#q').onkeydown=e=>{if(e.key==='Enter')search()};setup();</script></html>'''
